{
var seed = GetInt(parameters, "seed", context.Seed);
var coverage = GetFloat(parameters, "coverage", 0.5f);
var scale = GetFloat(parameters, "scale", 3f);
var patchSize = GetFloat(parameters, "patchSize", 0.5f);
var edgeSoftness = GetFloat(parameters, "edgeSoftness", 0.4f);
var darkMoss = GetColor(parameters, "darkMoss", Color.FromRgb(40, 90, 30));
var lightMoss = GetColor(parameters, "lightMoss", Color.FromRgb(80, 160, 50));
var spotColor = GetColor(parameters, "spotColor", Color.FromRgb(120, 180, 60));
var colorVar = GetFloat(parameters, "colorVariation", 0.3f);
var detail = GetFloat(parameters, "detail", 0.3f);
var heightEffect = GetFloat(parameters, "heightEffect", 0.3f);
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var hasBase = inputs.Length > 0 && inputs[0] != null;
var input = hasBase ? inputs[0]! : null;
var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var dR = darkMoss.R / 255f; var dG = darkMoss.G / 255f; var dB = darkMoss.B / 255f;
var lR = lightMoss.R / 255f; var lG = lightMoss.G / 255f; var lB = lightMoss.B / 255f;
var sR = spotColor.R / 255f; var sG = spotColor.G / 255f; var sB = spotColor.B / 255f;

// Tileable period for noise
var period = Math.Max(1, (int)MathF.Round(scale * 4f));

// Pre-compute a Voronoi-like patch distribution for organic clusters
var patchCount = Math.Max(1, (int)(patchSize * 12));
var patches = new (float x, float y, float strength, float hueShift)[patchCount];
for (var i = 0; i < patchCount; i++)
{
    patches[i] = (
        HashToUnit(i * 7, seed, 111),
        HashToUnit(i * 13, seed * 3, 222),
        0.5f + HashToUnit(i * 17, seed * 5, 333) * 0.5f,
        (HashToUnit(i * 23, seed * 7, 444) - 0.5f) * 2f
    );
}

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // --- Base surface ---
    float baseR, baseG, baseB;
    if (hasBase && input != null)
    {
        var (br, bg, bb, _) = input.GetPixel(x, y);
        baseR = br; baseG = bg; baseB = bb;
    }
    else
    {
        // Default base: stone-like gray
        var stoneNoise = TileableFractalNoise(
            u * 2f, v * 2f,
            Math.Max(1, 2), 2, 0.5f, 2f, seed + 50);
        baseR = 0.5f + (stoneNoise - 0.5f) * 0.2f;
        baseG = 0.45f + (stoneNoise - 0.5f) * 0.15f;
        baseB = 0.4f + (stoneNoise - 0.5f) * 0.15f;
    }

    // --- Multi-scale moss signal ---
    // Large-scale patch structure
    var largePatch = TileableFractalNoise(
        u * scale * 0.5f, v * scale * 0.5f,
        period, 3, 0.6f, 2.2f, seed);

    // Medium-scale detail
    var mediumPatch = TileableFractalNoise(
        u * scale * 1.5f, v * scale * 1.5f,
        Math.Max(1, period / 2), 2, 0.5f, 2f, seed + 100);

    // Small-scale fine detail
    var finePatch = 0f;
    if (detail > 0f)
    {
        finePatch = TileableFractalNoise(
            u * scale * 4f, v * scale * 4f,
            Math.Max(1, period / 3), 2, 0.5f, 2f, seed + 200);
    }

    // --- Distance to nearest patch center ---
    var minPatchDist = float.MaxValue;
    var nearestHueShift = 0f;
    var nearestStrength = 0f;

    foreach (var (px, py, ps, ph) in patches)
    {
        var dx = u - px;
        var dy = v - py;
        if (dx > 0.5f) dx -= 1f; else if (dx < -0.5f) dx += 1f;
        if (dy > 0.5f) dy -= 1f; else if (dy < -0.5f) dy += 1f;
        var dist = dx * dx + dy * dy;
        if (dist < minPatchDist)
        {
            minPatchDist = dist;
            nearestHueShift = ph;
            nearestStrength = ps;
        }
    }

    var invPatchDist = MathF.Exp(-minPatchDist * 20f / Math.Max(patchSize, 0.1f));

    // --- Combine signals into moss presence ---
    var mossSignal = largePatch * 0.5f + mediumPatch * 0.3f + invPatchDist * 0.2f;

    if (detail > 0f)
    {
        mossSignal += finePatch * detail * 0.15f;
    }

    // Apply coverage threshold
    var threshold = 1f - coverage;
    var hasMoss = mossSignal > threshold;

    if (!hasMoss)
    {
        // No moss — show base surface
        buffer.SetPixel(x, y, baseR, baseG, baseB, 1f);
        return;
    }

    // --- Moss intensity (0..1 within moss area) ---
    var mossIntensity = (mossSignal - threshold) / (1f - threshold);
    mossIntensity = Math.Clamp(mossIntensity, 0f, 1f);

    // Soft edges
    if (edgeSoftness > 0f)
    {
        mossIntensity = mossIntensity * mossIntensity * (3f - 2f * mossIntensity);
    }

    // --- Moss color ---
    // Color varies with intensity, patch hash, and height
    var hShift = nearestHueShift * colorVar;

    // Height effect: moss looks thicker/thinner
    if (heightEffect > 0f)
    {
        var heightNoise = TileableFractalNoise(
            u * scale * 2f + 100f, v * scale * 2f + 100f,
            Math.Max(1, period / 2), 1, 0.5f, 2f, seed + 300);
        mossIntensity += (heightNoise - 0.5f) * heightEffect * 0.3f;
        mossIntensity = Math.Clamp(mossIntensity, 0f, 1f);
    }

    // Blend between dark and light moss
    var mossR = Lerp(dR, lR, mossIntensity);
    var mossG = Lerp(dG, lG, mossIntensity);
    var mossB = Lerp(dB, lB, mossIntensity);

    // Per-patch color variation
    mossR = Math.Clamp(mossR + hShift * 0.3f, 0f, 1f);
    mossG = Math.Clamp(mossG + hShift * 0.5f, 0f, 1f);
    mossB = Math.Clamp(mossB + hShift * 0.2f, 0f, 1f);

    // Bright spot details
    if (detail > 0f)
    {
        var spotNoise = TileableFractalNoise(
            u * scale * 6f, v * scale * 6f,
            Math.Max(1, period / 2), 1, 0.5f, 2f, seed + 400);
        if (spotNoise > 0.7f)
        {
            var spot = (spotNoise - 0.7f) / 0.3f * detail;
            mossR = Lerp(mossR, sR, spot * 0.4f);
            mossG = Lerp(mossG, sG, spot * 0.4f);
            mossB = Lerp(mossB, sB, spot * 0.4f);
        }
    }

    // --- Compose: blend moss over base ---
    // Moss partially occludes the base surface
    var mossOpacity = mossIntensity * (0.7f + coverage * 0.3f);

    var finalR = Lerp(baseR, mossR, mossOpacity);
    var finalG = Lerp(baseG, mossG, mossOpacity);
    var finalB = Lerp(baseB, mossB, mossOpacity);

    // Height effect: shadow at thick moss areas
    if (heightEffect > 0f && mossIntensity > 0.6f)
    {
        var shadow = (mossIntensity - 0.6f) / 0.4f * heightEffect * 0.15f;
        finalR = Math.Clamp(finalR - shadow, 0f, 1f);
        finalG = Math.Clamp(finalG - shadow * 0.8f, 0f, 1f);
        finalB = Math.Clamp(finalB - shadow * 0.7f, 0f, 1f);
    }

    // Brightness and contrast
    var outR = Math.Clamp(finalR + brightness, 0f, 1f);
    var outG = Math.Clamp(finalG + brightness, 0f, 1f);
    var outB = Math.Clamp(finalB + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        outR = (outR - 0.5f) * factor + 0.5f;
        outG = (outG - 0.5f) * factor + 0.5f;
        outB = (outB - 0.5f) * factor + 0.5f;
    }

    if (invert) { outR = 1f - outR; outG = 1f - outG; outB = 1f - outB; }

    buffer.SetPixel(x, y, Math.Clamp(outR, 0f, 1f), Math.Clamp(outG, 0f, 1f), Math.Clamp(outB, 0f, 1f), 1f);
});

return buffer;
}
